import{_ as t,o as a,c as o,a2 as i}from"./chunks/framework.Bix3-HpO.js";const u=JSON.parse('{"title":"FXT Theme Updates","description":"FXT Theme Updates","frontmatter":{"title":"FXT Theme Updates","description":"FXT Theme Updates","weight":130,"extra":{"order":130},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/fxt/theme-updates"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/fxt/theme-updates"}],["meta",{"property":"og:title","content":"FXT Theme Updates"}],["meta",{"property":"og:description","content":"FXT Theme Updates"}],["meta",{"name":"twitter:title","content":"FXT Theme Updates"}],["meta",{"name":"twitter:description","content":"FXT Theme Updates"}]]},"headers":[],"relativePath":"docs/fxt/theme-updates.md","filePath":"docs/fxt/theme-updates.md"}'),s={name:"docs/fxt/theme-updates.md"};function r(n,e,l,d,h,c){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="fxt-theme-updates" tabindex="-1">FXT Theme Updates <a class="header-anchor" href="#fxt-theme-updates" aria-label="Permalink to &quot;FXT Theme Updates&quot;">​</a></h1><p>FXT theme includes an automatic update system that keeps your theme up to date with the latest features, security patches, and improvements.</p><hr><h2 id="automatic-updates" tabindex="-1">Automatic Updates <a class="header-anchor" href="#automatic-updates" aria-label="Permalink to &quot;Automatic Updates&quot;">​</a></h2><h3 id="how-updates-work" tabindex="-1">How Updates Work <a class="header-anchor" href="#how-updates-work" aria-label="Permalink to &quot;How Updates Work&quot;">​</a></h3><p>FXT theme automatically checks for updates through the DinoMatic update server:</p><ol><li><strong>License Verification</strong>: Updates are only available for registered themes</li><li><strong>Version Check</strong>: The theme checks for new versions periodically</li><li><strong>Update Notification</strong>: You&#39;ll be notified when updates are available</li><li><strong>One-Click Update</strong>: Install updates directly from WordPress dashboard</li></ol><h3 id="update-requirements" tabindex="-1">Update Requirements <a class="header-anchor" href="#update-requirements" aria-label="Permalink to &quot;Update Requirements&quot;">​</a></h3><p>To receive theme updates:</p><ul><li><strong>Valid License</strong>: Your theme must be registered with a valid license key</li><li><strong>Active License</strong>: The license must be activated in FXT Options</li></ul><hr><h2 id="manually-checking-for-updates" tabindex="-1">Manually Checking for Updates <a class="header-anchor" href="#manually-checking-for-updates" aria-label="Permalink to &quot;Manually Checking for Updates&quot;">​</a></h2><ol><li>In WordPress dashboard, go to <strong>Appearance</strong> → <strong>Themes</strong></li><li>Look for the FXT theme in your installed themes</li><li>If an update is available, you&#39;ll see an &quot;Update Available&quot; notification</li><li>Click <strong>Update Now</strong> to install the latest version</li></ol><hr><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="update-issues" tabindex="-1">Update Issues <a class="header-anchor" href="#update-issues" aria-label="Permalink to &quot;Update Issues&quot;">​</a></h3><p>If you encounter problems with updates:</p><ol><li><strong>Check License</strong>: Ensure your license is valid and activated</li><li><strong>Server Connection</strong>: Verify your server can connect to dinomatic.com</li><li><strong>File Permissions</strong>: Check that WordPress can write to the themes directory</li></ol><h3 id="manual-update" tabindex="-1">Manual Update <a class="header-anchor" href="#manual-update" aria-label="Permalink to &quot;Manual Update&quot;">​</a></h3><p>If automatic updates fail:</p><ol><li>Download the latest theme version from your DinoMatic account</li><li>Upload the theme files through WP dashboard</li><li>Install and replace the previous version</li><li>Clear any caching options</li></ol><hr><h2 id="next-step" tabindex="-1">Next Step <a class="header-anchor" href="#next-step" aria-label="Permalink to &quot;Next Step&quot;">​</a></h2><p><a href="/docs/fxt/child-theme">FXT Child Theme</a></p>',24)])])}const m=t(s,[["render",r]]);export{u as __pageData,m as default};
